54		async getFrequentlyBoughtTogether({
55			styleIds,
56			exclude = [],
57		}: FrequentlyBoughtTogetherQueryDto): Promise<FrequentlyBoughtTogetherResponseDto> {
58			let fallbackUsed = false;
59	
60			this.logger.debug('[getFrequentlyBoughtTogether] Starting FBT fetch', {
61				styleIds,
62				excludeCount: exclude.length,
63			});
64	
65			try {
66				const styles = await Promise.all(
67					styleIds.map((id) => this.stylesService.getStyleById({ styleId: id })),
68				);
69	
70				const validStyles = styles.filter(Boolean) as IStyleBase[];
71				if (validStyles.length === 0) {
72					throw new BadRequestException(
73						`No styles found for styleIds: ${styleIds.join(', ')}`,
74					);
75				}
76	
77				this.logger.debug('[getFrequentlyBoughtTogether] Valid styles found', {
78					validCount: validStyles.length,
79					inputCount: styleIds.length,
80				});
81	
82				const cartCategoryIds = validStyles
83					.map((_style) => _style.primary_category_id)
84					.filter((id): id is number => id !== null && id !== undefined);
85				let correlatedCategoryIds: number[] = [];
86	
87				for (const style of validStyles) {
88					if (style.primary_category_id) {
89						const correlations =
90							await this.categoryCorrelationsService.getTopCorrelatedCategories({
91								primaryCategoryId: style.primary_category_id,
92								limit: 4,
93								exclude: cartCategoryIds,
94							});
95	
96						correlatedCategoryIds.push(...correlations.map((corr) => corr.edge_id));
97					}
98				}
99	
100				correlatedCategoryIds = [...new Set(correlatedCategoryIds)];
101				this.logger.debug('Found correlated categories', {
102					count: correlatedCategoryIds.length,
103					styleIds,
104				});
105	
106				if (correlatedCategoryIds.length === 0) {
107					this.logger.warn('No correlations found, using fallback', { styleIds });
108					correlatedCategoryIds = await this.stylesService.getMostPopularCategories({
109						limit: 4,
110					});
111					fallbackUsed = true;
112				}
113	
114				this.logger.log(
115					'[getFrequentlyBoughtTogether] Fetching popular styles from correlated categories',
116					{
117						correlatedCategoryIds,
118					},
119				);
120				const allPopularStyles = await this.stylesService.getMostPopularStylesByCategories({
121					categoryIds: correlatedCategoryIds,
122					limit: 5,
123					excludeIds: [...styleIds, ...exclude],
124				});
125				const allPopularStylesIds = allPopularStyles.map((_style) => _style.style_id);
126				this.logger.log('[getFrequentlyBoughtTogether] Popular styles fetched', {
127					count: allPopularStylesIds.length,
128				});
129	
130				const currentStyleColor = await this.getCurrentColorStyle(styleIds[0]);
131				const products = await this.productHydrationService.hydrateProducts({
132					styleIds: allPopularStylesIds,
133					currentStyleColor,
134				});
135				this.logger.log('[getFrequentlyBoughtTogether] Products hydrated', {
136					hydratedCount: products.length,
137				});
138	
139				const productsByStyleId = new Map(products.map((p) => [p.style_id, p]));
140				const activeStyleIds = new Set(products.map((p) => p.style_id));
141	
142				const filteredAllPopularStyles = allPopularStyles.filter((s) =>
143					activeStyleIds.has(s.style_id),
144				);
145	
146				const stylesWithCategory = filteredAllPopularStyles.filter(
147					(style): style is IStyleBase & { primary_category_id: number } =>
148						style.primary_category_id !== null,
149				);
150				const selectedStyleIds = this.selectRandomStylesFromCategories(
151					stylesWithCategory,
152					correlatedCategoryIds,
153				);
154	
155				const selectedStyles = allPopularStyles.filter((style) =>
156					selectedStyleIds.includes(style.style_id),
157				);
158				const sortedStyles = selectedStyles
159					.sort((a, b) => b.purchases_count - a.purchases_count)
160					.slice(0, 4);
161				const finalStyleIds = sortedStyles.map((style) => style.style_id);
162	
163				let finalProducts = finalStyleIds
164					.map((id) => productsByStyleId.get(id))
165					.filter((p): p is IRelatedProduct => p !== undefined);
166	
167				if (finalStyleIds.length < 4) {
168					this.logger.debug('Using fallback for additional recommendations', {
169						currentCount: finalStyleIds.length,
170						targetCount: 4,
171					});
172	
173					const regularResult = await this.getFrequentlyBoughtTogetherByRootCategories({
174						styleIds,
175						exclude: finalStyleIds.concat(exclude),
176					});
177	
178					const additionalProducts = regularResult.frequently_bought_together
179						.filter((product) => !finalStyleIds.includes(product.style_id))
180						.slice(0, 4 - finalStyleIds.length);
181	
182					finalProducts = finalProducts.concat(additionalProducts);
183	
184					this.logger.debug('Added additional recommendations', {
185						count: additionalProducts.length,
186					});
187				}
188	
189				this.logger.debug('Selected styles for recommendations', {
190					count: finalProducts.length,
191				});
192	
193				return {
194					style_ids: styleIds,
195					frequently_bought_together: finalProducts,
196					fallback_used: fallbackUsed,
197				};
198			} catch (error) {
199				this.logger.error(
200					`Error getting frequently bought together for styles ${styleIds.join(', ')}: ${(error as Error).message}`,
201					(error as Error).stack,
202				);
203				throw error;
204			}
205		}
