284			exclude = [],
285		}: FrequentlyBoughtTogetherRootCategoriesQueryDto): Promise<FrequentlyBoughtTogetherRootCategoriesResponseDto> {
286			let fallbackUsed = false;
287	
288			this.logger.log(
289				'[getFrequentlyBoughtTogetherByRootCategories] Starting root category FBT fetch',
290				{
291					styleIds,
292					excludeCount: exclude.length,
293				},
294			);
295	
296			try {
