423		async getFrequentlyBoughtTogetherV2({
424			styleId,
425			colorId,
426			exclude = [],
427			limit = 4,
428			diversifyCategories = false,
429			favorOppositeType = false,
430		}: FrequentlyBoughtTogetherV2QueryDto): Promise<FrequentlyBoughtTogetherV2ResponseDto> {
431			try {
432				const style = await this.stylesService.getStyleById({ styleId });
433				if (!style) {
434					throw new BadRequestException(`No style found for styleId: ${styleId}`);
435				}
436	
437				const useDiversified = diversifyCategories || favorOppositeType;
438				let copurchasedStyleIds: number[];
439	
440				if (useDiversified) {
441					let seedStyleType: string | null = null;
442					if (favorOppositeType) {
443						const mvStyle = await this.stylesMvService.getByStyleId({ styleId });
444						seedStyleType = mvStyle?.style_type ?? null;
445					}
446	
447					const diversifiedCopurchases =
448						await this.styleCopurchasesService.getTopCopurchasesDiversified({
449							styleId,
450							limit,
451							excludeIds: [styleId, ...exclude],
452							diversifyCategories,
453							favorOppositeType,
454							seedStyleType,
455						});
456	
457					if (diversifiedCopurchases.length === 0) {
458						this.logger.debug('No diversified copurchases found, falling back to v1', {
459							styleId,
460						});
461						const v1Result = await this.getFrequentlyBoughtTogether({
462							styleIds: [styleId],
463							exclude,
464						});
465	
466						return {
467							style_id: styleId,
468							frequently_bought_together: v1Result.frequently_bought_together.slice(
469								0,
470								limit,
471							),
472							fallback_used: true,
473						};
474					}
475	
476					copurchasedStyleIds = diversifiedCopurchases.map((c) => c.paired_style_id);
477				} else {
478					const copurchases = await this.styleCopurchasesService.getTopCopurchases({
479						styleId,
480						limit,
481						excludeIds: [styleId, ...exclude],
482					});
483	
484					if (copurchases.length === 0) {
485						this.logger.debug('No copurchases found, falling back to v1', { styleId });
486						const v1Result = await this.getFrequentlyBoughtTogether({
487							styleIds: [styleId],
488							exclude,
489						});
490	
491						return {
492							style_id: styleId,
493							frequently_bought_together: v1Result.frequently_bought_together.slice(
494								0,
495								limit,
496							),
497							fallback_used: true,
498						};
499					}
500	
501					copurchasedStyleIds = copurchases.map((c) => c.paired_style_id);
502				}
503	
504				let currentStyleColor: IStyleColorBase | null = null;
505				if (colorId) {
506					currentStyleColor = await this.styleColorsService.getStyleByStyleAndColorId({
507						styleId,
508						colorId,
509					});
510				}
511				currentStyleColor ??= await this.getCurrentColorStyle(styleId);
512	
513				const products = await this.productHydrationService.hydrateProducts({
514					styleIds: copurchasedStyleIds,
515					currentStyleColor,
516				});
517	
518				this.logger.debug('FBT v2 results', {
519					styleId,
520					resultCount: products.length,
521				});
522	
523				return {
524					style_id: styleId,
525					frequently_bought_together: products,
526					fallback_used: false,
527				};
528			} catch (error) {
529				this.logger.error(
530					`Error getting FBT v2 for style ${styleId}: ${(error as Error).message}`,
531					(error as Error).stack,
532				);
533				throw error;
534			}
535		}
536	}
